import 'package:flutter/material.dart'; import '../../../core/theme/app_theme.dart'; class RenameDeviceDialog extends StatelessWidget { final String currentName; final ValueChanged<String> onRename; const RenameDeviceDialog({super.key, required this.currentName, required this.onRename}); @override Widget build(BuildContext context) { final ctrl = TextEditingController(text: currentName); return AlertDialog(backgroundColor: AppTheme.darkCard, shape: RoundedRectangleBorder(borderRadius: BorderRadius.circular(20)), title: const Text('Rename Device', style: TextStyle(color: AppTheme.darkText)), content: TextField(controller: ctrl, autofocus: true, style: const TextStyle(color: AppTheme.darkText), decoration: InputDecoration(hintText: 'Device name', hintStyle: const TextStyle(color: AppTheme.darkSubtext), filled: true, fillColor: AppTheme.darkBorder, border: OutlineInputBorder(borderRadius: BorderRadius.circular(10), borderSide: BorderSide.none))), actions: [TextButton(onPressed: () => Navigator.pop(context), child: const Text('Cancel', style: TextStyle(color: AppTheme.darkSubtext))), TextButton(onPressed: () { Navigator.pop(context); onRename(ctrl.text.trim()); }, child: const Text('Rename', style: TextStyle(color: AppTheme.primaryColor, fontWeight: FontWeight.w700)))]); } }